mapper.select:
SELECT * FROM spc_alarm_event 
WHERE STATUS = 'ACTIVE'

    AND INDICATOR_ID IN

        #{id}



    AND FAC_CODE = #{facCode}

ORDER BY START_TIME DESC

SELECT * FROM spc_alarm_event 
WHERE START_TIME >= #{startTime}
AND START_TIME <= #{endTime}

    AND INDICATOR_ID IN (
        SELECT ID FROM spc_indicator WHERE SYSTEM_CODE = #{systemCode}
    )


    AND INDICATOR_ID IN (
        SELECT ID FROM spc_indicator WHERE CLASS_CODE = #{classCode}
    )


    AND FAC_CODE = #{facCode}

ORDER BY start_time DESC

SELECT * FROM spc_alarm_event 
WHERE INDICATOR_ID = #{indicatorId}

    AND FAC_CODE = #{facCode}

ORDER BY START_TIME DESC

    LIMIT #{limit}

SELECT COUNT(*) FROM spc_alarm_event 
WHERE START_TIME >= #{startTime}
AND START_TIME <= #{endTime}



            AND OOS = 1


            AND OOW = 1


            AND OOC = 1


            AND OO3 = 1




    AND FAC_CODE = #{facCode}

select JOB_ID as jobId, sum(OOS) as oosCount,sum(OOW) as oowCount,sum(OOC) as oocCount,sum(OO3) as oo3Count,sum(NORMAL) as normalCount from spc_alarm_event
where 1=1

    and FAC_CODE = #{facCode}


    and JOB_ID in

        #{jobId}



    and POINT in

        #{point}



    and CLASS_CODE = #{classCode}


    and INDICATOR_LEVEL = #{indicatorLevel}


    and  PEEK_VALUE_TIME >= #{startTime} 


    and  PEEK_VALUE_TIME <= #{endTime} 

group by JOB_ID

SELECT sar.id as id, sar.job_id as jobId, si.system_code as systemCode, si.id as indicatorId, si.indicator_name as IndicatorName, si.indicator_level as IndicatorLevel, sar.`point` as point, si.point_unit as PointUnit, si.class_code, si.start_value as startValue, si.step as step, si.target_value as targetValue, si.end_value as endValue, sar.ucl_value as uclValue, sar.lcl_value as lclValue, sar.uwl_value as uwlValue, sar.lwl_value as lwlValue, sar.usl_value as uslValue, sar.lsl_value as lslValue, sar.u3l_value as u3lValue, sar.l3l_value as l3lValue, sar.oos as oos, sar.ooc as ooc, sar.oow as oow, sar.oo3 as oo3, sar.normal as normal, sar.peek_value as pointValue, sar.PEEK_VALUE_TIME as eventTime, sn.content as content FROM spc_alarm_event sar JOIN spc_indicator si ON sar.indicator_id = si.id LEFT JOIN spc_note sn ON sar.id = sn.business_key WHERE 1 = 1
and si.FAC_CODE = #{facCode}
and si.class_code = #{classCode}
and si.config_type = #{configType}
and sar.PEEK_VALUE_TIME >= #{startTime}
and sar.PEEK_VALUE_TIME <= #{endTime}
AND sar.point IN
#{item}
AND sar.job_id IN
#{item}
AND si.system_code IN
#{item}
ORDER BY sar.peek_value_time DESC

SELECT COUNT(*) as total_events, AVG(FIRST_VALUE) as avg_first_value, AVG(LAST_VALUE) as avg_last_value, MAX(FIRST_VALUE) as max_first_value, MIN(FIRST_VALUE) as min_first_value, MAX(LAST_VALUE) as max_last_value, MIN(LAST_VALUE) as min_last_value, SUM(CASE WHEN LAST_VALUE > FIRST_VALUE THEN 1 ELSE 0 END) as increasing_events, SUM(CASE WHEN LAST_VALUE < FIRST_VALUE THEN 1 ELSE 0 END) as decreasing_events, SUM(CASE WHEN LAST_VALUE = FIRST_VALUE THEN 1 ELSE 0 END) as stable_events FROM spc_alarm_event WHERE START_TIME >= #{startTime} AND START_TIME <= #{endTime} AND FIRST_VALUE IS NOT NULL AND LAST_VALUE IS NOT NULL
and JOB_ID in
#{jobId}
AND FAC_CODE = #{facCode}
GROUP BY JOB_ID

SELECT ae.id, ae.segment_id, ae.indicator_id, ae.job_id, ae.indicator_name, ae.point, CASE WHEN ae.oos = 1 THEN 'OOS' WHEN ae.oow = 1 THEN 'OOW' WHEN ae.ooc = 1 THEN 'OOC' WHEN ae.oo3 = 1 THEN 'OO3' ELSE 'UNKNOWN' END AS alarm_type, ae.start_time, ae.end_time, ae.duration_seconds, ROUND(ae.duration_seconds / 60.0, 2) AS duration_minutes, ROUND(ae.duration_seconds / 3600.0, 2) AS duration_hours, ae.point_count, ae.max_value, ae.max_value_time, ae.min_value, ae.min_value_time, ae.avg_value, ae.first_value, ae.first_value_time, ae.last_value, ae.last_value_time, ae.end_value, ae.end_value_time, CASE WHEN ae.first_value IS NOT NULL AND ae.last_value IS NOT NULL THEN ae.last_value - ae.first_value ELSE NULL END AS value_change, CASE WHEN ae.first_value IS NOT NULL AND ae.end_value IS NOT NULL THEN ae.end_value - ae.first_value ELSE NULL END AS first_to_end_change, CASE WHEN ae.peek_value IS NOT NULL AND ae.end_value IS NOT NULL THEN ae.end_value - ae.peek_value ELSE NULL END AS peek_to_end_recovery, CASE WHEN ae.first_value IS NOT NULL AND ae.last_value IS NOT NULL AND ae.first_value != 0 THEN ROUND(((ae.last_value - ae.first_value) / ae.first_value) * 100, 2) ELSE NULL END AS value_change_rate_percent, CASE WHEN ae.first_value IS NOT NULL AND ae.last_value IS NOT NULL THEN CASE WHEN ae.last_value > ae.first_value THEN '上升' WHEN ae.last_value < ae.first_value THEN '下降' ELSE '无变化' END ELSE '无数据' END AS value_trend, ae.peek_value, ae.peek_time, ae.severity_level, ae.status, CASE WHEN ae.status = 'ACTIVE' THEN '进行中' WHEN ae.status = 'RESOLVED' THEN '已解决' WHEN ae.status = 'IGNORED' THEN '已忽略' WHEN ae.status = 'TIMEOUT' THEN '超时' ELSE ae.status END AS status_desc, ae.notification_sent, ae.handled_by, ae.handle_time, ae.handle_note, ae.create_time, ae.update_time FROM spc_alarm_event ae WHERE ae.start_time >= #{startTime} AND ae.start_time <= #{endTime}
AND ae.severity_level = #{severityLevel}
AND ae.status = #{status}
AND ae.indicator_name LIKE CONCAT('%', #{indicatorName}, '%')
AND ae.point = #{point}
AND (
ae.oos = 1 ae.oow = 1 ae.ooc = 1 ae.oo3 = 1 1=0
)
ORDER BY ae.start_time DESC, ae.severity_level DESC
LIMIT #{limit}
OFFSET #{offset}

SELECT update_time
FROM spc_alarm_event
WHERE segment_id = #{segmentId}
